import { useParams, Link } from "react-router-dom";
import Card from "../components/Card";

const resources = {
  "ai-and-ml": [
    { name: "Coursera ML", url: "https://www.coursera.org/learn/machine-learning" },
    { name: "Kaggle Learn", url: "https://www.kaggle.com/learn" },
    { name: "Google ML Crash Course", url: "https://developers.google.com/machine-learning/crash-course" },
    { name: "Fast.ai", url: "https://www.fast.ai/" }
  ],

  "web-development": [
    { name: "MDN Docs", url: "https://developer.mozilla.org" },
    { name: "FreeCodeCamp", url: "https://www.freecodecamp.org" },
    { name: "W3Schools", url: "https://www.w3schools.com" },
    { name: "Frontend Masters", url: "https://frontendmasters.com" }
  ],

  "cloud-and-devops": [
    { name: "AWS Training", url: "https://aws.amazon.com/training/" },
    { name: "Azure Learn", url: "https://learn.microsoft.com/en-us/training/" }
  ],

  "cybersecurity": [
    { name: "TryHackMe", url: "https://tryhackme.com/" },
    { name: "Hack The Box", url: "https://www.hackthebox.com/" }
  ]
};

export default function DomainDetailPage() {
  const { name } = useParams();

  // ✅ Fix: match URL format
  const domainKey = name.toLowerCase();
  const links = resources[domainKey] || [];

  // ✅ Get timeline
  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  // ✅ Daily roadmap generator
  const generateRoadmap = (domain, days) => {
  const roadmap = [];

  if (domain === "ai-and-ml") {
    const topics = [
      "Python Basics",
      "Control Statements",
      "Functions",
      "Numpy",
      "Pandas",
      "Data Visualization",
      "Statistics",
      "Linear Regression",
      "Logistic Regression",
      "Decision Trees",
      "SVM",
      "Model Evaluation",
      "Project Work",
      "Deep Learning Basics",
      "Neural Networks",
      "Final Project"
    ];

    let topicIndex = 0;

    for (let i = 1; i <= days; i++) {
      // move to next topic every few days dynamically
      if (i % Math.ceil(days / topics.length) === 0 && topicIndex < topics.length - 1) {
        topicIndex++;
      }

      roadmap.push(`Day ${i}: ${topics[topicIndex]}`);
    }
  }

  else if (domain === "web-development") {
    const topics = [
      "HTML Basics",
      "CSS Styling",
      "Flexbox & Grid",
      "JavaScript Basics",
      "DOM Manipulation",
      "ES6 Concepts",
      "React Basics",
      "Components & Props",
      "State Management",
      "API Integration",
      "Projects",
      "Node.js",
      "Express.js",
      "MongoDB",
      "Full Stack Project"
    ];

    let topicIndex = 0;

    for (let i = 1; i <= days; i++) {
      if (i % Math.ceil(days / topics.length) === 0 && topicIndex < topics.length - 1) {
        topicIndex++;
      }

      roadmap.push(`Day ${i}: ${topics[topicIndex]}`);
    }
  }

  else {
    for (let i = 1; i <= days; i++) {
      roadmap.push(`Day ${i}: Learn fundamentals + practice`);
    }
  }

  return roadmap;
};

  const roadmapSteps = generateRoadmap(domainKey, totalDays);

  return (
    <div className="space-y-8">
      <Card
        title={`${name.replace(/-/g, " ")} Roadmap`}
        description="Daily learning plan based on your timeline."
      >
        
        {/* Back */}
        <div className="mb-6">
          <Link to="/domains" className="text-sm text-blue-600 underline">
            ← Back to Domains
          </Link>
        </div>

        {/* Resources */}
        <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
          {links.map((link, index) => (
            <a
              key={index}
              href={link.url}
              target="_blank"
              rel="noreferrer"
              className="rounded-[2rem] border border-slate-300 bg-gradient-to-br from-green-100 to-emerald-100 p-6 shadow-md hover:shadow-lg transition dark:border-slate-600 dark:from-slate-700 dark:to-slate-700 dark:shadow-slate-950/50"
            >
              <h3 className="text-lg font-semibold text-slate-900 dark:text-slate-50">
                {link.name}
              </h3>
              <p className="mt-2 text-sm text-slate-700 dark:text-slate-300">
                Click to open resource
              </p>
            </a>
          ))}
        </div>

        {/* Daily Roadmap */}
        <div className="mt-8">
          <h2 className="text-xl font-semibold text-slate-900 dark:text-slate-50 mb-4">
            Daily Roadmap ({timeline})
          </h2>

          <div className="space-y-3 max-h-[400px] overflow-y-auto">
            {roadmapSteps.map((step, index) => (
              <div
                key={index}
                className="rounded-xl bg-green-100 dark:bg-slate-700 p-4"
              >
                {step}
              </div>
            ))}
          </div>
        </div>

      </Card>
    </div>
  );
}
